svg.script:
/*
	Psychrometric Chart DISPLAY
	1.0.0 - 16/02/2016

	Copyright CAREL Industries s.p.a
*/

var pressione = 101325;
var trugiada = -5800.2206;
var tpartenza = 1.3914993;
var percarr = -0.048640239;
var Dt = 4.17648e-5;
var tempo = -1.44521e-8;
var efficienza = 0;
var stimaPL = 6.5459673;

var xPos = 0;
var yPos = 0;

var load_ok = true;

if(webMI.query["temp1"] != "" && webMI.query["hum1"] != "")	{
	/*if(webMI.query["tooltip1"]!=""){
		webMI.gfx.setText("descr_1", webMI.query["tooltip1"]);
	}*/		
	plotPoints(1);
	plotPoints(2);
}else{
	/*webMI.gfx.setVisible("legend1",false);		
	webMI.gfx.setText("descr_1", "");*/
}



function plotPoints(pointnum){
	webMI.data.subscribeBlock([webMI.query["temp"+pointnum],webMI.query["hum"+pointnum],webMI.query["active_class"]], [], function(e){
		load_ok = true;
		for (i=0;i<e.length;i++){
			if (e[i].value=="NaN" || typeof(e[i])=="undefined" || e[i].value=="undefined"){
				load_ok = false;
				break;
			}
		}

		var temp = e[0].value;
		var hum = e[1].value;
		var active_class = e[2].value; 
		var specificHum = calculateHum(temp, hum);

		//webMI.gfx.setText("hum_shown"+pointnum, specificHum);

		xPos = parseFloat(webMI.gfx.getCenterX("point0_0")) + webMI.translate(temp,0,55,0,parseFloat(webMI.gfx.getCenterX("point55_0"))-parseFloat(webMI.gfx.getCenterX("point0_0")));	
		yPos = parseFloat(webMI.gfx.getCenterY("point55_0")) - webMI.translate(specificHum,0,30,0,parseFloat(webMI.gfx.getCenterY("point55_0"))-parseFloat(webMI.gfx.getCenterY("point55_30")));

		webMI.gfx.setVisible("reference"+pointnum, true);
		webMI.gfx.setMoveX("reference"+pointnum, xPos);
		webMI.gfx.setMoveY("reference"+pointnum, yPos);

		//area_class setting
		if (active_class == 0){
			webMI.gfx.setVisible("recommended_envelope", false);
			webMI.gfx.setVisible("A1_envelope", false);
			webMI.gfx.setVisible("A2_envelope", false);
			webMI.gfx.setVisible("A3_envelope", false);
			webMI.gfx.setVisible("A4_envelope", false);
		}else if (active_class == 1){
			webMI.gfx.setVisible("recommended_envelope", true);
			webMI.gfx.setVisible("A1_envelope", false);
			webMI.gfx.setVisible("A2_envelope", false);
			webMI.gfx.setVisible("A3_envelope", false);
			webMI.gfx.setVisible("A4_envelope", false);
		}else if (active_class == 2){
			webMI.gfx.setVisible("recommended_envelope", false);
			webMI.gfx.setVisible("A1_envelope", true);
			webMI.gfx.setVisible("A2_envelope", false);
			webMI.gfx.setVisible("A3_envelope", false);
			webMI.gfx.setVisible("A4_envelope", false);
		}else if (active_class == 3){
			webMI.gfx.setVisible("recommended_envelope", false);
			webMI.gfx.setVisible("A1_envelope", false);
			webMI.gfx.setVisible("A2_envelope", true);
			webMI.gfx.setVisible("A3_envelope", false);
			webMI.gfx.setVisible("A4_envelope", false);
		}else if (active_class == 4){
			webMI.gfx.setVisible("recommended_envelope", false);
			webMI.gfx.setVisible("A1_envelope", false);
			webMI.gfx.setVisible("A2_envelope", false);
			webMI.gfx.setVisible("A3_envelope", true);
			webMI.gfx.setVisible("A4_envelope", false);
		}else if (active_class == 5){
			webMI.gfx.setVisible("recommended_envelope", false);
			webMI.gfx.setVisible("A1_envelope", false);
			webMI.gfx.setVisible("A2_envelope", false);
			webMI.gfx.setVisible("A3_envelope", false);
			webMI.gfx.setVisible("A4_envelope", true);
		}
		//hiding/showing loading
		if (load_ok){
			webMI.gfx.setVisible("loading_bg", false);
		}else{
			webMI.gfx.setVisible("loading_bg", true);
		}
	});
}

function calculateHum(temp, hum){
	// this calculation is valid for temp > 0	
	var TtOA = 273.15+temp;
	var PvstOA = Math.exp((trugiada/TtOA)+tpartenza+(percarr*TtOA)+(Dt*Math.pow(TtOA,2)+(tempo*Math.pow(TtOA,3))+(efficienza*Math.pow(TtOA,4))+(stimaPL*Math.log(TtOA))));
	var xOA = 0.62198*hum*0.01*PvstOA/(pressione-hum*0.01*PvstOA);
	var specHum = xOA * 1000;
	specHum = specHum.toFixed(1);
	return specHum;
}

webMI.callExtension("SYSTEM.LIBRARY.ATVISE.QUICKDYNAMICS.Tooltip", {"id":"reference1", "text":webMI.query["tooltip1"] + ""});
webMI.callExtension("SYSTEM.LIBRARY.ATVISE.QUICKDYNAMICS.Tooltip", {"id":"reference2", "text":webMI.query["tooltip2"] + ""});
